package com.example.sso.controller;

import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import java.io.IOException;

@Controller
public class LogoutController {

    @GetMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response,
                       @RequestParam(value = "next", required = false) String nextUrl) throws IOException {
        
        // Invalidate the current session
        if (request.getSession(false) != null) {
            request.getSession(false).invalidate();
        }

        // Determine the redirection URL
        String redirectUrl = (nextUrl != null && !nextUrl.isEmpty()) ? nextUrl : "/"; // Default to home page if 'next' is not provided

        // Perform the redirect
        response.sendRedirect(redirectUrl);
    }
}